funding_df = pd.DataFrame(funding_data)
funding_df['Amount'] = pd.to_numeric(funding_df['Amount'], errors='coerce').fillna(0)

extracted_projects = {} 

for doc in civic_docs:
    text = doc['text']
    lines = text.splitlines()
    current_project = None
    recent_lines = []

    for line in lines:
        line = line.strip()
        if not line:
